const w = $('Prepara Prompt').first().json;
const text = $input.first().json.content[0].text.trim();

const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Nessun JSON trovato. Output Claude: ' + text.slice(0, 200));

let p;
try { p = JSON.parse(m[0]); }
catch (e) { throw new Error('JSON non parsabile: ' + m[0].slice(0, 200)); }

const pMap = {
  immediata: 'entro poche ore',
  entro_24h: 'entro 24 ore',
  bassa: 'il prima possibile'
};

return [{ json: {
  data_ricezione: new Date().toISOString(),
  nome: w.nome || '',
  email: w.email || '',
  azienda: w.azienda || '',
  telefono: w.telefono ? "'" + w.telefono : '',
  messaggio: w.messaggio || '',
  classificazione: p.classificazione,
  score: p.score,
  reasoning: p.reasoning,
  priorita_risposta: p.priorita_risposta,
  descrizione_priorita: pMap[p.priorita_risposta] || 'il prima possibile'
} }];
